import{c as a,S as t,j as s,m as i}from"./chunks/framework.slzObTu2.js";const u=JSON.parse('{"title":"Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),r={name:"index.md"};function o(n,e,l,h,p,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report" tabindex="-1">Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report <a class="header-anchor" href="#Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report" aria-label="Permalink to &quot;Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report {#Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report}&quot;">​</a></h1><p><strong>Authors:</strong> Sam Abbott, Samuel Brand and Sebastian Funk.</p><p><strong>Last updated:</strong> 20 May 2026. This is a live report, re-run as new data arrive, so the estimates change between updates.</p><p><a href="https://doi.org/10.5281/zenodo.20312758" target="_blank" rel="noreferrer"><img src="https://zenodo.org/badge/1243778099.svg" alt="DOI"></a></p><p><strong>Abstract.</strong> An outbreak of Ebola disease caused by Bundibugyo virus (BVD) is ongoing in the Democratic Republic of the Congo (DRC), with cases also detected across the border in Uganda. Estimating the likely current size of the outbreak is useful for the response, but most cases are not yet reported and have to be inferred from the data streams that are available. The Imperial College London report (McCabe et al., <a href="https://www.imperial.ac.uk/mrc-global-infectious-disease-analysis/research-themes/preparedness-and-response-to-emerging-threats/report-ebola-18-05-2026/" target="_blank" rel="noreferrer">18 May 2026</a>) estimates the size with two analyses, geographic spread from the cases exported to Uganda and back-calculation from suspected deaths in DRC. Building on that work, we re-analyse the same problem as a single joint Bayesian model over the latent cumulative case count, fitting all streams together with priors on the nuisance parameters that the report varies in scenario sweeps. Beyond the exported cases and DRC deaths the report uses, we condition on two further streams, the reported cases in DRC (with an ascertainment component) and the deaths among exported cases in Uganda. We also add a no-onward-transmission projected-deaths counterfactual, a one-week-ahead forecast and an onset-to-death delay sensitivity analysis, and replace two closed-form approximations (the deaths convolution and the small-growth-rate exports term) with their exact forms. We report the joint posterior over the cumulative case count from current data; to separate the effect of newer data from the change in method we also fit the model to the data as of the report, comparing against both a joint reimplementation of the report&#39;s approach and its original published estimates.</p><p><strong>Use of AI:</strong> The model code and analysis were drafted by a language model and reviewed and revised under human oversight; the named authors are responsible for that oversight.</p><p><strong>Why our numbers differ from the Imperial report.</strong> Two reasons. First, the method: we fit all data streams jointly in a single Bayesian model rather than combining separate scenario analyses (the abstract above and the analysis page list the full set of changes). Second, the data: we use the 20 May 2026 snapshot (sources per <a href="https://github.com/epiforecasts/BVDOutbreakSize/blob/main/data/observations.toml" target="_blank" rel="noreferrer"><code>data/observations.toml</code></a>), more recent than the 16 May 2026 figures in the McCabe et al. report. To separate these two effects we also refit the model to the report&#39;s own data. The joint posterior assumes a single common cut-off for every data stream, so the counts must be kept in sync to the same date.</p><p>The <a href="https://epiforecasts.io/BVDOutbreakSize/dev/analysis" target="_blank" rel="noreferrer">analysis</a> lays out each deviation alongside the matching Imperial method.</p><h2 id="Running" tabindex="-1">Running <a class="header-anchor" href="#Running" aria-label="Permalink to &quot;Running {#Running}&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recurse-submodules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/seabbs/BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/examples/analysis.jl</span></span></code></pre></div><p>Render the docs page (executes the literate and produces HTML at <code>docs/build/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.develop(PackageSpec(path=pwd())); Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/make.jl</span></span></code></pre></div><p>Updating the observation counts for a new sitrep is a single-file edit of <code>data/observations.toml</code>; the literate picks the new numbers up automatically.</p><h2 id="Results" tabindex="-1">Results <a class="header-anchor" href="#Results" aria-label="Permalink to &quot;Results {#Results}&quot;">​</a></h2><p>Each push to <code>main</code> regenerates the model outputs as part of the documentation build and publishes them as a GitHub Release. The <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases/latest" target="_blank" rel="noreferrer">latest release</a> bundles the saved result tables and plots, thinned posterior draws, a copy of the input <code>observations.toml</code> that produced them, a <code>site.zip</code> snapshot of the rendered report site, and <code>analysis.html</code>, a self-contained single-file copy of the report that opens offline (<a href="https://github.com/epiforecasts/BVDOutbreakSize/releases/latest/download/analysis.html" target="_blank" rel="noreferrer">download the latest</a>); the same artifacts are written to the repository&#39;s <code>output/</code> directory on each build. Browse <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases" target="_blank" rel="noreferrer">all releases</a> for earlier output bundles — major versions of the report are kept as GitHub Releases.</p><p>The rendered report is published from the <a href="https://github.com/epiforecasts/BVDOutbreakSize/tree/gh-pages" target="_blank" rel="noreferrer"><code>gh-pages</code> branch</a>, where past and development versions of the analysis page can be found.</p><p>To regenerate the same outputs locally:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/run.jl</span></span></code></pre></div><p>This fits the model and writes the CSVs to an <code>output/</code> directory at the repository root (<code>output/posterior_summary.csv</code>, <code>cumulative_cases_by_stream.csv</code>, <code>imperial_comparison.csv</code>, <code>scenario_coverage.csv</code>, <code>posterior_draws.csv</code>, and a copy of <code>observations.toml</code>).</p><h2 id="Submodules" tabindex="-1">Submodules <a class="header-anchor" href="#Submodules" aria-label="Permalink to &quot;Submodules {#Submodules}&quot;">​</a></h2><ul><li><code>external/bdbv-linelist-analysis</code> — Bayesian reanalysis of the 2012 Isiro BDBV line list (Rosello et al. 2015). Source of the informative onset-to-death gamma shape and scale priors.</li></ul><h2 id="Citation" tabindex="-1">Citation <a class="header-anchor" href="#Citation" aria-label="Permalink to &quot;Citation {#Citation}&quot;">​</a></h2><p>If you use or build on this project, please cite the three works this repository depends on:</p><ul><li><p><strong>This project</strong> — Abbott, S., Brand, S., Funk, S. (2026). <em>BVDOutbreakSize: joint forward-generative Turing model for the 2026 DRC Bundibugyo outbreak.</em> <a href="https://github.com/epiforecasts/BVDOutbreakSize" target="_blank" rel="noreferrer">https://github.com/epiforecasts/BVDOutbreakSize</a>. DOI: <a href="https://doi.org/10.5281/zenodo.20312758" target="_blank" rel="noreferrer">10.5281/zenodo.20312758</a>.</p></li><li><p><strong>Imperial report</strong> that this work re-implements — McCabe, R., Ebbarnezh, L., Okware, S., Fotsing, R., Koua, E., Mbaka, P., Lofungola, A., van Elsland, S. L., McMenamin, M., Ferguson, N., le Polain de Waroux, O., Cori, A. (2026). <em>Estimation of the size of the outbreak of Ebola disease caused by Bundibugyo virus in DRC.</em> Imperial College London, 18 May 2026. <a href="https://www.imperial.ac.uk/mrc-global-infectious-disease-analysis/research-themes/preparedness-and-response-to-emerging-threats/report-ebola-18-05-2026/" target="_blank" rel="noreferrer">Report page</a>.</p></li><li><p><strong>Onset-to-death delay reanalysis</strong> that this work uses for delay priors — Funk, S. (2026). <em>bdbv-linelist-analysis: Bayesian reanalysis of the 2012 Isiro Bundibugyo line list.</em> <a href="https://github.com/sbfnk/bdbv-linelist-analysis" target="_blank" rel="noreferrer">https://github.com/sbfnk/bdbv-linelist-analysis</a>.</p></li></ul><h2 id="Further-references" tabindex="-1">Further references <a class="header-anchor" href="#Further-references" aria-label="Permalink to &quot;Further references {#Further-references}&quot;">​</a></h2><ul><li><p>Rosello et al., <em>Ebola virus disease in DRC, 1976–2014</em>, eLife 2015. Original Isiro 2012 onset-to-death gamma point estimate.</p></li><li><p>Imai et al., <em>Estimating the potential total number of novel coronavirus cases in Wuhan City</em>, Imperial COVID-19 Response Team Report 1, 17 January 2020. Methodological template for Method 1.</p></li><li><p>Charniga et al., <em>Best practices for estimating and reporting epidemiological delay distributions</em>, PLOS Computational Biology 2024. Followed for the delay-distribution reporting here.</p></li></ul>`,26)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
